fun solve(sx: Long, sy: Long, tx: Long, ty: Long): Long {
    if (sx == tx && sy == ty) return 0

    var steps = 0
    while (sx < tx && sy < ty) {
        if (sx > sy) {
            sx += sy
        } else {
            sy += sx
        }
        steps++
    }

    if (sx != tx || sy != ty) {
        return -1
    }

    if (sx < tx) {
        steps += (tx - sx)
    } else if (sy < ty) {
        steps += (ty - sy)
    }

    return steps
}
